1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	type Item = { type: string };
10	type Step = { items: Item[] };
11	type Scenario = { steps: Step[] };
12	
13	export function processScenario(scenario: unknown): unknown {
14	  const { steps } = scenario as Scenario;
15	  const items = steps[0].items;
16	  const basePremium = items.reduce(
17	    (sum, item) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
18	    0,
19	  );
20	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
21	}
